// L1 FSM resolveNextStage port · iso-comportamental state-machine.ts
const JOURNEY_STAGES = {
  ACQUIRE: ['lead_capture','qualified','discovery_call','proposal_generated','won'],
  ONBOARD: ['kickoff','auto_discovery_complete','send_intake_form','intake_received','brand_discovery','review_handoff'],
  PRODUCE: ['brief_intake','research','creative_concepts','production','qa_review','launch','optimize'],
  ALWAYS_ON: ['monitoring','anomaly_detected','recovery_dispatched'],
  REVIEW: ['data_collection','qbr_drafted','qbr_reviewed','qbr_sent'],
  GROWTH: ['expansion_identified','pitch_prepared','committed'],
};
const DB_TRIGGER_MAP = {
  manual:'manual', webhook:'webhook', cron:'cron',
  cascade_done:'webhook', anomaly_detected:'cron',
  hitl_resolved:'webhook', resume_stuck:'manual',
};

const body = $('Webhook L1 dispatch').first().json.body;
const existing = $input.first().json;
const existingRow = Array.isArray(existing) && existing.length > 0 ? existing[0] : null;
const journey = body.journey;
const trigger = body.trigger_type;
const stages = JOURNEY_STAGES[journey];

let nextStage;
if (body.stage) {
  nextStage = body.stage;
} else if (!stages || stages.length === 0) {
  nextStage = null;
} else if (!existingRow || existingRow.current_stage == null) {
  nextStage = stages[0];
} else if (trigger === 'resume_stuck') {
  nextStage = existingRow.current_stage;
} else if (trigger === 'hitl_resolved' || trigger === 'cascade_done') {
  const idx = stages.indexOf(existingRow.current_stage);
  nextStage = (idx < 0 || idx >= stages.length - 1) ? existingRow.current_stage : stages[idx + 1];
} else if (journey === 'ALWAYS_ON' && trigger === 'anomaly_detected') {
  nextStage = 'anomaly_detected';
} else {
  nextStage = existingRow.current_stage;
}

return [{
  json: {
    body,
    existing_row: existingRow,
    next_stage: nextStage,
    db_trigger: DB_TRIGGER_MAP[trigger] || 'manual',
    trigger_type_original: trigger,
  }
}];

