// Build DispatchResult canonical · defensive against unrun branch nodes.
function safeNode(name) {
  try { return $(name).first()?.json; } catch (e) { return null; }
}

const body = $('Webhook L1 dispatch').first().json.body;
const nextStage = $('Resolve next stage').first().json.next_stage;
const l2 = $input.first().json;

// journey_id from whichever persist branch ran
const insertOut = safeNode('POST insert row');
const patchOut = safeNode('PATCH update row');
const insertRow = Array.isArray(insertOut) ? insertOut[0] : insertOut;
const patchRow = Array.isArray(patchOut) ? patchOut[0] : patchOut;
const persistedRow = insertRow || patchRow;
const journeyId = persistedRow?.id || null;

const journey = body.journey;
const isStub = ['REVIEW','ACQUIRE','GROWTH'].includes(journey);

let dispatchStatus, l2Target, l2Error;
if (isStub) {
  dispatchStatus = 'stubbed';
  l2Target = 'stub:' + journey;
} else if (l2 && (l2.ok === false || (typeof l2.statusCode === 'number' && l2.statusCode >= 400) || l2.error)) {
  dispatchStatus = 'failed';
  l2Target = null;
  l2Error = (l2.message || l2.error || JSON.stringify(l2)).toString().slice(0, 200);
} else {
  dispatchStatus = 'dispatched';
  const ZR = $env.ZERO_RISK_API_URL || 'https://zero-risk-platform.vercel.app';
  const N8 = $env.N8N_BASE_URL || 'https://n8n-production-72be.up.railway.app';
  l2Target = journey === 'ONBOARD' ? ZR + '/api/onboarding' :
             journey === 'PRODUCE' ? N8 + '/webhook/campaign-orchestrator' :
             journey === 'ALWAYS_ON' ? ZR + '/api/journey/event-log' : null;
}

function computeNextCheck() {
  if (isStub) return null;
  if (journey === 'PRODUCE') return new Date(Date.now() + 5 * 60 * 1000).toISOString();
  if (journey === 'ALWAYS_ON') return new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
  return null;
}

return [{
  json: {
    ok: dispatchStatus !== 'failed',
    journey_id: journeyId,
    journey: journey,
    dispatch_status: dispatchStatus,
    l2_target: l2Target,
    next_check_at: computeNextCheck(),
    error: l2Error,
    details: { mode: isStub ? 'stub' : (journey === 'PRODUCE' ? 'n8n_webhook' : 'http'), engine: 'n8n-l1', next_stage: nextStage },
  }
}];
